import { WorkflowContext, StepOutput } from 'mastra';
import { z } from 'zod';

const expectedSchemas = {
  customerData: z.object({
    id: z.string(),
    name: z.string(),
    email: z.string().email()
  }),
  toolResult: z.object({
    result: z.any(),
    success: z.boolean()
  })
};

export const detectWorkflowDrift = async (ctx: WorkflowContext, output: StepOutput) => {
  const stepName = ctx.currentStep?.name;
  const schema = expectedSchemas[stepName as keyof typeof expectedSchemas];

  if (schema) {
    const validation = schema.safeParse(output);
    if (!validation.success) {
      console.error(`Schema drift detected in ${stepName}:`, validation.error);
      return {
        drift: true,
        step: stepName,
        errors: validation.error.errors
      };
    }
  }
  return { drift: false };
};

import { MemoryContext } from 'mastra';

export const detectStaleMemory = (memory: MemoryContext): { stale: boolean; ttlViolations: number } => {
  const now = Date.now();
  const ttlThreshold = 7 * 24 * 60 * 60 * 1000; // 7 days

  const violations = memory.entries.filter(entry => {
    const age = now - (entry.timestamp || 0);
    return age > ttlThreshold;
  }).length;

  return {
    stale: violations > 0,
    ttlViolations: violations
  };
};

import { ToolCallResult } from 'mastra/agent';

export const detectToolDrift = (toolResult: ToolCallResult) => {
  const expectedStructure = {
    result: 'required',
    success: 'required',
    error: 'optional'
  };

  const missingFields = Object.entries(expectedStructure)
    .filter(([key, required]) => required === 'required' && !(key in toolResult))
    .map(([key]) => key);

  return {
    malformed: missingFields.length > 0,
    missingFields,
    toolName: toolResult.toolName
  };
};

