import { MiddlewareFn } from 'mastra';
import { z } from 'zod';

const schemas = {
  customerLookup: z.object({
    id: z.string(),
    name: z.string().min(1),
    email: z.string().email().optional()
  })
};

export const validationMiddleware: MiddlewareFn = async (ctx, next) => {
  const beforeOutput = ctx.output;

  // Validate and fix output
  const stepSchema = schemas[ctx.currentStep?.name as keyof typeof schemas];
  if (stepSchema) {
    const parsed = stepSchema.parse(beforeOutput);
    ctx.output = parsed;
  }

  await next();
};

import { AgentContext, MemoryContext } from 'mastra';

export const freshMemoryOnly = (ctx: AgentContext): MemoryContext => {
  const ttl = 7 * 24 * 60 * 60 * 1000; // 7 days
  const now = Date.now();

  return {
    ...ctx.memory,
    entries: ctx.memory.entries.filter(entry => {
      const age = now - (entry.timestamp || 0);
      return age < ttl;
    })
  };
};

import { ToolCallResult } from 'mastra/agent';

export const normalizeToolResponse = (rawResult: any): ToolCallResult => {
  return {
    toolName: rawResult.toolName || 'unknown',
    success: Boolean(rawResult.result),
    result: rawResult.result || rawResult.data || null,
    error: rawResult.error || rawResult.message || null,
    timestamp: Date.now()
  };
};

